import jibo = require('jibo');
import {CircadianState} from 'jibo-common-types';
import { CircadianStateMachine } from '../CircadianStateMachine';
import { libraries } from '@be/be-framework';
import cu = libraries.jibo_cai_utils;
import sm = libraries.jibo_state_machine;

export { } // For Type definition purposes

/**
 * @class ChooseTimeState
 * @extends {State}
 * @internal
 * @private
 */
export class ChooseTimeState extends sm.State {

	private daytimeState: sm.State;
	private nighttimeState: sm.State;

	constructor(private parent: CircadianStateMachine) {
		super(parent, CircadianState.TIME_OF_DAY);
		
		this.onEntry = (transition: sm.Transition) => {
			const skill = this.parent.parent.parent;
			// We transition to falling asleep state upon entry if it is night
			skill.log.info(`Entering ${this.name}.`);

			const pod = this.parent.parent.currentPoD;
			if (pod.basic === cu.PartOfDayBasic.NIGHT) {
				this.transitionTo(this.nighttimeState);
			} else {
				this.transitionTo(this.daytimeState);
			}
		};
	}

	/**
	 * Install the transitions to use depending on what time of day we enter 
	 * the state.
	 * @param {State} daytimeState to transition to if its day
	 * @param {State} nighttimeState to transition to if its night
	 */
	public installTransitions(daytimeState: sm.State, nighttimeState: sm.State) {
		this.daytimeState = daytimeState;
		this.nighttimeState = nighttimeState;
		this.addInternalTransition(`Daytime`, daytimeState);
		this.addInternalTransition(`Nighttime`, nighttimeState);
	}
}
