const short_idle_queries = require('../../config/idle_animation_short_time_config.json');

export interface TransitionExpressionOptions {
	animPlayOptions?: AnimPlayOptions;
	brightnessGoal?: number;
}

export interface AnimPlayOptions {
	query: AnimQuery;
	name?: string;
	randomOrientation?: boolean;
	loops?: number;
	muteAudio?: boolean;
	eyeOnly?: boolean;
}

/**
 * Enumerated musing types
 * @property {String} BIG
 * @property {String} SMALL
 * @intdocs
 */
export enum MusingType {
	BIG = 'BIG',
	SMALL = 'SMALL'
}

/**
 * Format of queries from the idle animation config file
 * @export
 * @property {AnimQuery} query to enter into animation database
 * @property {string} startDate starting date from which the query is valid
 * @property {string} endDate end date after which the query is invalid
 * @property {number} weight to use in idle animation selection. Must be greater than 0.
 * @property {string[]} holiday list. Only show animations it the user celebrates one of these.
 * @property {string[]} notHoliday list. Only show animation if the user does not celebrate any of these.
 * @intdocs
 */
export interface IdleQuery {
	query: {
		category: string,
		includeMeta: string[],
		includeSomeMeta: string[],
		excludeMeta: string[]
	};
	startDate: string;
	endDate: string;
	weight: number;
	holiday?: string[];
	notHoliday?: string[];
}
// export class AnimationHandle {
