// }

export interface AnimationHandle {
	promise: Promise<any>,
	cancel: () => void
}

class AnimationElement implements CancelableElement {
	animationHandle: AnimationHandle = null;

	constructor(public parent: CircadianExpression, public animPlayOptions: AnimPlayOptions, public cancelWhenNewAdded: boolean, private visual: boolean = false) { }

	async promiseGenerator() {
		const start = Date.now();
		this.animationHandle = await this.parent.playAnimDBAnimation(this.animPlayOptions);
		if (this.animationHandle) {
			await this.animationHandle.promise;
			this.animationHandle = null

			if (this.visual) {
				// Log analytics that we played a visual animation element
				jibo.analytics.track('Idle behavior', { idle_behavior_class: 'visual' });
			}
		}
	}

	cancel() {
		if (this.animationHandle) {
			this.animationHandle.cancel();
			this.animationHandle = null;
		}
	}
}

