class RampBrightnessElement implements CancelableElement {

	constructor(private goal: number, private skill: Idle) { }
	
	async promiseGenerator() {
		// Sanitize the input to be in [0, 0.4] range
		this.goal = Math.max(Math.min(this.goal, CircadianExpression.SCREEN_BRIGHTNESS_AWAKE), CircadianExpression.SCREEN_BRIGHTNESS_ASLEEP);

		let currentBacklight: number;
		try {
			currentBacklight = await timeout(promisify<number>(cb => jibo.system.getBacklight(cb)), 1000);
		} catch (error) {
			this.skill.log.error('Could not get current backlight value. Not setting backlight: ', error);
			throw error;  
		}
		
		// sanitize the input
		currentBacklight = Math.floor(currentBacklight * 10) / 10;

		this.skill.log.info(`Attempting to change brightness from ${currentBacklight} to ${this.goal}.`);
		const increment = (currentBacklight > this.goal) ? -0.1 : 0.1; // Screen brightness only changes at increments of a tenth, e.g. there's no change between 0.10 and 0.19. The change occurs at 0.2.
		const iterations = Math.round(Math.abs((this.goal - currentBacklight)/increment)); // round to the nearest whole iteration
		for (let i = 1; i <= iterations; i++) {
			const val = Number((currentBacklight + i * increment).toFixed(1)); // Correct for floating point errors
			try {
				await timeout(promisify<null>(cb => jibo.system.setBacklight(val, cb)), 1000);
			} catch (error) {
				this.skill.log.warn(`Timeout while setting brightness to ${val}`);
			}
			this.skill.log.debug(`Brightness set to ${val}.`);
		}
	}

	cancel() {
		// there's no cancelling this
	}
}

export class CircadianExpression {

	// Screen brightness values for use in tests.
	static SCREEN_BRIGHTNESS_AWAKE = 0.4;
	static SCREEN_BRIGHTNESS_NAP = 0.3;
	static SCREEN_BRIGHTNESS_ASLEEP = 0.1;

	private cancellableQueue = new CancelableQueue();
	private transitionAnimMap = new Map<CircadianState, Map<CircadianState, TransitionExpressionOptions[]>>();
	private disturbedTransitionAnimMap = new Map<CircadianState, Map<CircadianState, TransitionExpressionOptions[]>>();
	protected weightedIdleQueries: libraries.jibo_cai_utils.WeightedRandomData[] = [];

	private skill = this.parent.parent;

	protected defaultIdleQuery: AnimQuery = {
		category: 'ib',
		includeMeta: ['ib-drive-playful'],
		includeSomeMeta: [],
		excludeMeta: []
	};
	constructor(public parent: CircadianManager) {
		this.transitionSetup();
	}

	/**
	 * Add a cancellable animation element to the animation queue
	 * @param {AnimPlayOptions} animPlayOptions to wrap in AnimationElement and add to the animation queue
	 */
	queueAnimation(animPlayOptions: AnimPlayOptions, cancelWhenNewAdded: boolean) {
		this.cancellableQueue.add(new AnimationElement(this, animPlayOptions, cancelWhenNewAdded));
	}

	/**
	 * Clear out the animation queue and cancel the current animation if there is one.
	 */
	clearAnimationQueue() {
		this.skill.log.info("Clearing animation queue.");
		this.cancellableQueue.clear();
	}


	/**
	 * Empty the animation queue (play everything inside)
	 */
	emptyAnimationQueue() {
		this.cancellableQueue.waitUntilEmpty();
	}

	/**
	 * Asynchronously play an animation and return the handle to that animation or null.
	 * @param {AnimPlayOptions} options for animation db query 
	 * @param {boolean} muteAudio whether the audio of the anim should be muted 
	 */
	async playAnimDBAnimation(options: AnimPlayOptions): Promise<AnimationHandle | null> {
		const query = options.query;
		let animation: Animation;

		let queryCategories = []; // for logging
		// if we've got a name
		if (options.name) {
			animation = jibo.animDB.getAnimByName(options.name);
			queryCategories.push("Named");
		} else if (query) {
			const animRes = jibo.animDB.query(query);
			animation = _.sample(animRes.matching);

			if (query.category) {
				queryCategories.push(query.category);
			} else if (query.categories) {
				queryCategories.push(...queryCategories);
			} else {
				queryCategories.push('NoCategory');
			}
		} else {
			this.skill.log.error("Attempted to play animation with incompatible AnimPlayOptions.");
			return;
		}

		if (animation) {
			const animConfig: AnimConfig = {
				cache: libraries.jibo_cai_utils.CacheUtils.GlobalCacheName
			};

			if (options.randomOrientation) {
				animConfig.orientation = (Math.random() > 0.5) ? Orientation.LEFT : Orientation.RIGHT;
			}

			let debugMsg = `Playing '${queryCategories}' animation '${animation.name}'`;
			if (animConfig.orientation) {
				debugMsg += ` with orientation '${Orientation[animConfig.orientation]}'`;
			}
			this.skill.log.debug(debugMsg);

			if (typeof options.loops === 'number') {
				animConfig.loops = options.loops;
			}

			// Mutes, a value of true means that channel is NOT muted
			if (options.eyeOnly) {
				animConfig.mutes = { AUDIO: false, SCREEN: true, BODY: false };
			} else if (options.muteAudio) {
				animConfig.mutes = { AUDIO: false, SCREEN: true, BODY: true };
			}

			const playback = await animation.createFromConfig(animConfig);
			const animationHandle = {
				promise: playback.play(),
				cancel: () => playback.stop()
			}

			return animationHandle;
		} else {
			this.skill.log.warn(`Couldn't find any animations for options: ${JSON.stringify(options)}`);
		}
	}

	/**
	 * Play an animation by name. Defaults to non-random orientation and unmuted audio
	 * @param {string} name of the animation to be played
	 */
	async playAnimationByName(name: string): Promise<AnimationHandle | null> {
		// set up a default config object
		const animPlayOptions: AnimPlayOptions = {
			query: null,
			name: name,
			randomOrientation: false,
			muteAudio: false,
		}

		return this.playAnimDBAnimation(animPlayOptions);
	}

	/**
	 * Add all the relevant animations for the transition thats occuring.
	 * @param {Transition} transition that is occuring.
	 */
	queueAnimationsForTransition(transition: sm.Transition) {
		const sourceState = this.replaceInternalTransitions(transition.getSourceState()) // Replace an internal transition source state with a visible transition source state. e.g. TIME_OF_DAY with RELAXED
		const destinationState = CircadianState[transition.getDestinationState().name];
		if (!destinationState) { // We should always have a destination state
			this.skill.log.error(`Queue animations called for invalid transitions ${sourceState} and ${destinationState}`);
			return;
		}

		// get the list of animations that corresponds with going from the source state to the transition state
		let transitions = this.transitionAnimMap.get(sourceState)
		if (!transitions) {
			this.skill.log.debug(`Circadian Expressions has no transition between ${sourceState} and ${destinationState}`);

			// We're coming from HJNoMatch so there's an unexpected global transition, make sure the eye gets reset.
			if (sourceState === CircadianState.HJ_NO_MATCH) {
				this.skill.log.info('Adding ForceEyeView element to queue to handle HJNoMatch global interruption.');
				this.cancellableQueue.add(new ForceEyeViewElement(this.skill));
			}
			return;
		}

		// Global event transitions clear the animation queue to prevent overlapping animations, but there are exceptions.
		if (this.shouldClearAnimationQueue(transition)) {
			this.clearAnimationQueue();
		}

		// If this transition will trigger an external animation (like an hj) don't put any new animations in the queue
		if (!this.transitionHasExternalAnimation(transition)) {
			// Was the transition caused by an environmental disturbance?
			if (this.isDisturbedTransition(transition)) {
				const disturbedTransitions = this.disturbedTransitionAnimMap.get(sourceState);
				if (disturbedTransitions && disturbedTransitions.get(destinationState)) {
					this.skill.log.info("Alternate transition found for environmental disturbance.");
					transitions = disturbedTransitions;
				}
			}

			const transitionAnimations: TransitionExpressionOptions[] = transitions.get(destinationState);
			if (transitionAnimations && transitionAnimations.length > 0) {
				transitionAnimations.forEach((value: TransitionExpressionOptions) => {
					if (value.animPlayOptions) {
						const cancelWhenNewAdded = (value.animPlayOptions.loops === 0); // Be able to cancel infitely looping anims
						this.queueAnimation(value.animPlayOptions, cancelWhenNewAdded);
					}

					if (typeof value.brightnessGoal === 'number') { // ignore 'undefined' and 'null' but accept '0'
						this.createRampBrightnessElement(value.brightnessGoal);
					}
				});
			} else {
				this.skill.log.info(`No transitions between ${sourceState} and ${destinationState}`);
			}

			// Edge case where we want to switch skills and open the menu once we're up and awake
			if (this.transitionCausedByScreenTouch(transition)) {
				this.cancellableQueue.add(new OpenMenuElement(this));
			}

			if (destinationState === CircadianState.ALERT) { // Edge case to ensure a fully open eye in alert mode. Intentionally put in queue after global clear.
				this.cancellableQueue.add(new CenterScreenDofsElement());
			}

			this.emptyAnimationQueue();
		} else {
			this.skill.log.info(`Transition should trigger external animation, not queueing any animations between ${sourceState} and ${destinationState}.`);
		}

		// Any transition that ends in alert or relaxed should ignore the promise queue in favor of reliably turning the brightness back up and recovering from any potential failures in brightness changes
		if (destinationState === CircadianState.ALERT || destinationState === CircadianState.RELAXED) {
			this.restoreScreenBrightness()
				.then(() => this.skill.log.info(`Brightness set to ${CircadianExpression.SCREEN_BRIGHTNESS_AWAKE}.`))
				.catch((error) => this.skill.log.error('Could not restore backlight: ', error));
		}
	}
	
	/**
	 * Return screen brightness to its standard level (0.4)
	 * @returns {Promise<null>} promise indicating state of set backlight command
	 */
	restoreScreenBrightness(): Promise<null> {
		return promisify<null>(cb => jibo.system.setBacklight(CircadianExpression.SCREEN_BRIGHTNESS_AWAKE, cb))
	}

	/**
	 * Is this transition caused by an environmental disturbance?
	 * @param {Transition} transition to check
	 */
	private isDisturbedTransition(transition: sm.Transition): boolean {
		// TODO: yeesh, is there a way to get around using strings here?
		return (transition.name === "TEvent: " + this.parent.circadianSM.events.faceAppeared.name ||
			transition.name === "TEvent: " + this.parent.circadianSM.events.noise.name ||
			transition.name === "TEvent: " + this.parent.circadianSM.events.screenTouched.name)
	}

	/**
	 * Does this transition trigger an external animation?
	 * @param {Transition} transition to check
	 * @return boolean indicating that this transition triggers an external animation
	 */
	private transitionHasExternalAnimation(transition: sm.Transition): boolean {
		// TODO: same "yeesh" as isDisturbedTransition
		return (transition.name === "TEvent: " + this.parent.circadianSM.events.hjHeard.name);
	}

	private transitionCausedByScreenTouch(transition: sm.Transition): boolean {
		return (transition.name === "TEvent: " + this.parent.circadianSM.events.screenTouched.name);
	}

	/**
	 * Should we clear out the animation queue for this transition?
	 * @param {Transition} transition to check
	 * @return boolean indicating that this transition should clear the animation queue
	 */
	private shouldClearAnimationQueue(transition: sm.Transition): boolean {
		let shouldClear = false;
		if (transition._isGlobal) {
			// TODO / Note to reviewers: Still trying to find a way to smooth out nap->head_touch->alert transition  (eye opens, stares, then closes and shudders awake)
			// Don't clear if we're waking up from a head pat, otherwise the eye opens and then closes again in order to wake up. 
			// if (transition.name !== "TEvent: " + this.parent.circadianSM.events.headTouch.name) {
			// 	shouldClear = true;
			// }
			shouldClear = true;
		}

		return shouldClear;
	}

	/**
	 * Replace internal transitions with their source states for the purposes of playing animations
	 * @param {CircadianState} sourceState state to check for replacement
	 * @return {CircadianState} replacement sourceState
	 */
	private replaceInternalTransitions(sourceState: sm.State): CircadianState {
		let replacementState: CircadianState = null;
		const sourceCircadianState = CircadianState[sourceState.name];

		if (sourceCircadianState) { // source is a valid circadian state, check if we need to replace internal transitions
			if (sourceCircadianState === CircadianState.TIME_OF_DAY) {
				replacementState = CircadianState.ALERT;
			}
		} else { // source is not a valid circadian state
			this.skill.log.error(`Unexpected transition. Replacing ${sourceState.name} with default ALERT.`); // this should never happen
			replacementState = CircadianState.ALERT;
		}

		if (replacementState) {
			this.skill.log.debug(`Replacing transition source state ${sourceState.name} with ${replacementState}`)
			return replacementState;
		} else {
			return sourceCircadianState;
		}
	}

	/**
	 * Setup the transition animation lists from one state to another.
	 * 
	 * The transition maps indicate what expressive steps should be taken when going from the map's state to the destination state. 
	 * i.e. The asleepMap's keys are states that can be transitioned to from ASLEEP, and the entries are the list of expressions 
	 * to do in sequence for that transition. 
	 */
	private transitionSetup() {
		// Circadian Prompted Transitions by source state
		const alertMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		alertMap.set(CircadianState.ASLEEP, [relaxedToSleep, fadeToAsleep]);
		alertMap.set(CircadianState.FALLING_ASLEEP, [drift, napPose, fadeToNap, napNoLoop]);

		const relaxedMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		relaxedMap.set(CircadianState.ALERT, [relaxedToActive]);
		relaxedMap.set(CircadianState.DAYTIME_NAP, [relaxedToNap, napPose, fadeToNap, napLoop])
		relaxedMap.set(CircadianState.FALLING_ASLEEP, [drift, yawn, napPose, fadeToNap, napNoLoop])
		relaxedMap.set(CircadianState.ASLEEP, [relaxedToSleep, fadeToAsleep]);

		const napMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		napMap.set(CircadianState.ALERT, [napToAlert]);
		napMap.set(CircadianState.RELAXED, [napToRelaxed]);
		napMap.set(CircadianState.FALLING_ASLEEP, [napNoLoop]);
		napMap.set(CircadianState.ASLEEP, [fallingAsleep, fadeToAsleep]);

		const fallingAsleepMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		fallingAsleepMap.set(CircadianState.ALERT, [napToAlert]);
		fallingAsleepMap.set(CircadianState.ASLEEP, [fallingAsleep, fadeToAsleep]);

		const asleepMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		asleepMap.set(CircadianState.WAKING_UP, [fadeToNap, sleepToNap, napLoop]);
		asleepMap.set(CircadianState.ALERT, [sleepToAwake]);

		const wakingUpMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		wakingUpMap.set(CircadianState.ALERT, [napToAlert]);
		wakingUpMap.set(CircadianState.RELAXED, [napToRelaxed]);

		const intentMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		intentMap.set(CircadianState.ASLEEP, [relaxedToSleep, fadeToAsleep]);
		intentMap.set(CircadianState.TURN_AWAY, [lookAway, fadeToNap, lookAwayEye]);

		const turnAwayMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		turnAwayMap.set(CircadianState.RELAXED, [lookBackTowards]);
		turnAwayMap.set(CircadianState.ASLEEP, [fadeToAsleep]);

		this.transitionAnimMap.set(CircadianState.ALERT, alertMap);
		this.transitionAnimMap.set(CircadianState.RELAXED, relaxedMap);
		this.transitionAnimMap.set(CircadianState.DAYTIME_NAP, napMap);
		this.transitionAnimMap.set(CircadianState.FALLING_ASLEEP, fallingAsleepMap);
		this.transitionAnimMap.set(CircadianState.ASLEEP, asleepMap);
		this.transitionAnimMap.set(CircadianState.WAKING_UP, wakingUpMap);
		this.transitionAnimMap.set(CircadianState.SELECT_INTENT, intentMap);
		this.transitionAnimMap.set(CircadianState.TURN_AWAY, turnAwayMap);

		// Environment caused transitions
		const wakingUpDisturbedMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		wakingUpDisturbedMap.set(CircadianState.RELAXED, [napDisturbedToRelaxed]);
		const napDisturbedMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		napDisturbedMap.set(CircadianState.RELAXED, [napDisturbedToRelaxed]);
		const asleepDisturbedMap = new Map<CircadianState, TransitionExpressionOptions[]>();
		asleepDisturbedMap.set(CircadianState.ALERT, [napPose]);

		this.disturbedTransitionAnimMap.set(CircadianState.DAYTIME_NAP, napDisturbedMap);
		this.disturbedTransitionAnimMap.set(CircadianState.WAKING_UP, wakingUpDisturbedMap);
		this.disturbedTransitionAnimMap.set(CircadianState.ASLEEP, asleepDisturbedMap);
	}

	/**
	 * Play a big musing
	 */
	playBigMusing() {
		this.skill.log.info("Playing big musing.");
		this.playMusing(MusingType.BIG).catch(error => {
			this.skill.log.error('Could not play big musing: ', error);
		});
	}

	/**
	 * Play a small musing
	 */
	playSmallMusing() {
		this.skill.log.info("Playing small musing.");
		this.playMusing(MusingType.SMALL).catch(error => {
			this.skill.log.error('Could not play small musing: ', error);
		});
	}

	/**
	 * Play a musing by choosing a random, date appropriate db query and appending musing meta tags.
	 * @param {MusingType} type of musing to play
	 * @return {Promise<AnimationHandle | null>} with either the handle to the musing or null 
	 */
	private async playMusing(type: MusingType) {
		let animQuery = await this.filterAndSelectQuery(type);

		if (!animQuery || this.weightedIdleQueries.length === 0) {
			this.skill.log.warn("No idle query is applicable, using default query:" + JSON.stringify(this.defaultIdleQuery));
			animQuery = this.defaultIdleQuery;
		} else {
			this.skill.log.info("Randomly chosen idle animation query:" + JSON.stringify(animQuery));
		}

		const musingInclude = (type === MusingType.BIG) ? ['ib-idle-short-time'] : ['ib-idle-long-time'];
		if (!animQuery.includeMeta) {
			animQuery.includeMeta = musingInclude;
		} else {
			animQuery.includeMeta.push(...musingInclude);
		}

		const options: AnimPlayOptions = {
			query: animQuery,
			randomOrientation: false,
			muteAudio: true
		}

		const cancelWhenNewAdded = false;
		const visualAnimation = true;
		this.cancellableQueue.add(new AnimationElement(this, options, cancelWhenNewAdded, visualAnimation));
		this.emptyAnimationQueue();
	}

	/**
	 * Filter the queries by todays date and randomly select one based on weight
	 * This must be done every time an idle animation is requested to properly use todays date.
	 * @param {MusingType} type of musing to play
	 * @return {AnimationGoalData} the randomly selected, date-applicable query.
	 */
	protected async filterAndSelectQuery(type: MusingType): Promise<AnimQuery> {
		// First filter queries by valid date
		const today = new Date();
		const celebratedHolidays = await BeSkill.plugins.holiday.getActiveHolidaySet();
		const unfilteredQueries = (type === MusingType.BIG) ? short_idle_queries : long_idle_queries; // Big musings happen when we've been in idle for a short time. Small musings happen when we've been in idle for a long time
		const idleQueries = unfilteredQueries.queries.filter((idleQuery: IdleQuery) => {
			if (idleQuery.holiday || idleQuery.notHoliday) {
				if (!this.isValidForUserHolidays(idleQuery, celebratedHolidays)) {
					return false;
				}
			}

			const queryStartDate = libraries.jibo_cai_utils.TimeUtils.dateFromString(idleQuery.startDate);
			const queryEndDate = libraries.jibo_cai_utils.TimeUtils.dateFromString(idleQuery.endDate);
			if (queryStartDate && queryEndDate) {
				return libraries.jibo_cai_utils.TimeUtils.dateWithinInterval(queryStartDate, today, queryEndDate);
			} else {
				this.skill.log.warn(`Malformed idle query found! ${JSON.stringify(idleQuery)}.`);
				return false;
			}
		});
		this.skill.log.debug(`Read ${idleQueries.length} date-applicable queries from config file.`);

		// Now put them in the right format to be chosen by random weight
		this.weightedIdleQueries = idleQueries.map((idleQuery: IdleQuery) => {
			return { data: idleQuery.query, weight: idleQuery.weight };
		});

		return _.cloneDeep(libraries.jibo_cai_utils.RandomUtils.weightedRandomSample(this.weightedIdleQueries));
	}

	/**
	 * Determine whether the user celebrates, or doesn't celebrate, the holiday in the idle query.
	 * @param {IdleQuery} query to check.
	 * @param {Set<string>} celebratedHolidays holidays the user celebrates
	 */
	private isValidForUserHolidays(query: IdleQuery, celebratedHolidays: Set<string>): boolean {
		let celebratesDesiredHoliday = true;
		let doesNotCelebrateExcludedHoliday = true;

		// make sure that the user celebrates one of the holidays in this list.
		if (query.holiday) {
			celebratesDesiredHoliday = query.holiday.some((holidayName) => {
				return celebratedHolidays.has(holidayName);
			})
		}

		// Make sure the user does not celebrate a holiday that this query excludes (takes precedence over the holiday list)
		if (query.notHoliday) {
			doesNotCelebrateExcludedHoliday = query.notHoliday.every((holidayName) => {
				return !celebratedHolidays.has(holidayName);
			})
		}

		return (celebratesDesiredHoliday && doesNotCelebrateExcludedHoliday);
	}

	/**
	 * Wrapped constructor to stub out in tests
	 * @param {Number} goal of brightness ramp
	 */
	private createRampBrightnessElement(goal: number) {
		this.cancellableQueue.add(new RampBrightnessElement(goal, this.skill));
	}
}

