import * as jibo from 'jibo';
export type Node = jibo.kb.Node;
export type Model = jibo.kb.Model;

export interface RootData {
	verbalNoMatchTimes: number[];
}

function initializeRootData(): RootData {
	return {
		verbalNoMatchTimes: []
	};
}

export interface RootNode extends Node {
	data: RootData;
}

export interface UserData {
	verbalNoMatchTimes: number[];
}

function initializeUserData(): UserData {
	return {
		verbalNoMatchTimes: []
	};
}

export interface UserNode extends Node {
	data: UserData;
}


export class KBModel {

	public model: Model;
	public rootNode: RootNode;
	public loopNode: Node;

	/**
	 * Initializes KB model
	 */
	async init(name = 'idle'): Promise<void> {
		this.model = jibo.kb.createModel('/' + name);
		this.rootNode = await this.model.loadRoot();
		if (!this.rootNode.data.verbalNoMatchTimes) {
			this.rootNode.data = initializeRootData();
			await this.rootNode.save();
		}

		const edges = this.rootNode.getEdges('loop');
		if (edges.length === 0) {
			this.loopNode = this.model.createNode('loop', {description: 'Loop Member Memory'});
			await this.loopNode.save();
			this.rootNode.addEdges(this.loopNode);
			await this.rootNode.save();
		} else if (edges.length === 1) {
			this.loopNode = await this.model.load(edges[0]);
		}
		else {
			throw new Error('Idle should only have one Loop Member Memory node');
		}
	}

	/**
	 * Clears all persisted data
	 */
	async clear() {
		this.rootNode.data = initializeRootData();
		await this.rootNode.save();
		const userEdges = this.loopNode.getEdges(Object.keys(this.loopNode.edges)); // TODO verify that this works
		for (let i = 0; i < userEdges.length; i++) {
			const userNode: UserNode = await this.model.load(userEdges[i]);
			userNode.data = initializeUserData();
			await userNode.save();
		}
	}

	/**
	 * Gets or creates a user node for a user id
	 * @param {string} userID
	 * @return {Node}
	 */
	async getUserNode(userID: string): Promise<UserNode> {
		const userEdges = this.loopNode.getEdges(userID);
		let userNode: UserNode;
		// If no user exists
		if (userEdges.length === 0) {
			userNode = this.model.createNode(userID);
			userNode.data = initializeUserData();
			await userNode.save();
			this.loopNode.addEdges(userNode);
			await this.loopNode.save();
		}
		// If user exists
		else {
			userNode = await this.model.load(userEdges[0]);
		}
		return userNode;
	}

	/**
	 * Marks that this user heard verbal HJNomatch today
	 * @param {Date} date
	 * @param {string} userID
	 */
	async markVerbalNoMatch(date: Date, userID?: string): Promise<void> {
		if (userID) {
			const userNode = await this.getUserNode(userID);
			userNode.data.verbalNoMatchTimes.push(date.getTime());
			await userNode.save();
		}
		this.rootNode.data.verbalNoMatchTimes.push(date.getTime());
		await this.rootNode.save();
	}

	/**
	 * Gets all times for a verbal nomatch
	 * @param {string} userID - If null then we return list of all latest hjnomatches
	 */
	async getVerbalNoMatches(userID?: string): Promise<Date[]> {
		if (userID) {
			const userNode = await this.getUserNode(userID);
			return userNode.data.verbalNoMatchTimes.map(t => new Date(t));
		}
		return this.rootNode.data.verbalNoMatchTimes.map(t => new Date(t));
	}
}
