/**
 * @fileOverview
 *
 * For automatic nighttime OTA updates unlikely to disrupt user interactions
 *
 * Created on 11/30/16.
 * @author Eric Ente <eric.ente@jibo.com>
 */

import { Utils } from '../Utils';
import jibo = require('jibo');
import { Idle } from '../Idle';
import { libraries } from '@be/be-framework'; 
import cu = libraries.jibo_cai_utils;

const OTA_KB = '/ota';
const A_WHILE = cu.TimeUtils.hoursToMs(36);

export class OTAUpdater {

	public updatesAvailable = false;
	private kbm: jibo.kb.Model = null;
	private skill: Idle = null;
	private otaDelay: number = 0;
	private enableDelayedCheck = false;
	private checkerDelay: number = 0;
	private enableBackup = false;
	private backupDelay: number = 0;

	constructor(idle: Idle) {
		this.skill = idle;
	}

	/**
	 * Initialize update helper - determine if and when to do checkForUpdates
	 * and/or downloadAndInstall
	 */
	public checkForUpdates() {
		this.otaDelay = 0;
		this.backupDelay = 0;
		this.checkerDelay = 0;
		this.enableBackup = false;
		this.enableDelayedCheck = false;
		this.updatesAvailable = false;
		this.kbm = jibo.kb.createModel(OTA_KB);
		this.kbm.loadRoot((err, root) => {
			this.skill.log.iferr(err, 'error loading OTA root from KB');
			if (!err && root && root.data) {
				if (!root.data.updatesAvailable) {
					if (root.data.lastUpdateCheck < Date.now() - A_WHILE) {
						//Make sure even lonely Jibos get updates:
						this._enableDelayedCheck();
					}
					else {
						this._enableBackup();
					}
				}
				else {
					this.skill.log.info(`Initializing Nighttime OTA Helper. Updates Available.`);
					this._enableUpdates();
				}
			}
			else {
				this.skill.log.info('Initializing Nighttime OTA Helper. OTA KB is empty.');
			}
		});
	}

	/**
	 * update ticker - triggers install or update checks at appropriate times
	 * @param {Number} sleepyTime - ms since Sleeping Idle started
	 */
	public update(sleepyTime: Number) {
		if (this.updatesAvailable && sleepyTime > this.otaDelay) {
			this.updatesAvailable = false;//don't need to re-trigger this
			this.skill.log.info('Initiating Nighttime OTA Update');
			jibo.scheduler.otaDownloadAndInstall((err) => {
				this.skill.log.iferr(err, `Nighttime OTA Update failed: ${err}`);
			});
		}
		else if (this.enableDelayedCheck && sleepyTime > this.checkerDelay) {
			this.enableDelayedCheck = false;
			this._delayedCheck();
		}
		else if (this.enableBackup && sleepyTime > this.backupDelay) {
			this.enableBackup = false;
			jibo.scheduler.backupRobot((err) => {
				if (err) {
					this.skill.log.error('nightly backup failed: ', err);
				}
				else {
					this.skill.log.info('nightly backup initiated');
				}
			});
		}
	}

	/**
	 * Randomize Lonely Jibo Update Check time otherwise all lonely Jibos
	 * would be hitting servers at exactly 11:30PM
	 */
	private _delayedCheck() {
		this.kbm.loadRoot((err, root) => {
			this.skill.log.iferr(err, 'error loading OTA root from KB on delayed check');
			jibo.scheduler.otaCheckUpdates((err, updateList) => {
				this.skill.log.iferr(err, 'error checking for updates in parent sleep');
				if (!err && updateList && updateList.length) {
					root.data.updatesAvailable = true;
					this.skill.log.info('Lonely Jibo Update Check - Yes Updates Available.');
				}
				else {
					this.skill.log.info('Lonely Jibo Update Check - No Updates Available.');
				}
				root.data.lastUpdateCheck = Date.now();
				root.save((err) => {
					this.skill.log.iferr(err, 'couldnt save on OTA check');
					if (root.data.updatesAvailable) {
						this._enableUpdates();//Backup will happen as part of downloadAndInstall process
					}
					else {
						this._enableBackup();//No updates to install tonight - do regular nightly backup
					}
				});
			});
		});
	}

	private _enableDelayedCheck() {
		this.checkerDelay = cu.TimeUtils.minutesToMs(Math.random() * 30);
		if (this.skill.debug) {//DEBUG MODE ONLY: Update Check happens in 0-1 minutes
			this.checkerDelay = cu.TimeUtils.minutesToMs(Math.random() * 1);
		}
		this.enableDelayedCheck = true;
		this.skill.log.info(`Initializing Nighttime OTA Helper. Will check for updates in ${this.checkerDelay / cu.TimeUtils.minutesToMs(1)} minutes`);
	}

	private _enableBackup() {
		this.backupDelay = cu.TimeUtils.minutesToMs(Math.round(Math.random() * 90) + 30);//30-120 minutes
		if (this.skill.debug) {//DEBUG MODE ONLY: Backup happens in 1-3 minutes
			this.backupDelay = cu.TimeUtils.minutesToMs(Math.round(Math.random() * 2) + 1);
		}
		this.backupDelay += this.checkerDelay;//ensure backup is delayed after a lonely-Jibo update check
		this.enableBackup = true;
		this.skill.log.info(`No Updates Available. Attempting backup in ${this.backupDelay / cu.TimeUtils.minutesToMs(1)} minutes.`);
	}

	/**
	 * We should attempt to download updates at the appropriate time
	 * prepares to OTA 30-120 minutes after sleep starts to stagger server hit
	 */
	private _enableUpdates() {
		this.otaDelay = cu.TimeUtils.minutesToMs(Math.round(Math.random() * 90) + 30);
		if (this.skill.debug) {//DEBUG MODE ONLY: Updates happen in 1-3 minutes
			this.otaDelay = cu.TimeUtils.minutesToMs(Math.round(Math.random() * 2) + 1);
		}
		this.otaDelay += this.checkerDelay;//ensure updates are delayed after a lonely-Jibo update check
		this.updatesAvailable = true;
		this.skill.log.info(`Updates Available. Attempting download in ${this.otaDelay / cu.TimeUtils.minutesToMs(1)} minutes.`);
	}
}
