import { libraries } from '@be/be-framework';
export import sm = libraries.jibo_state_machine;
export import cu = libraries.jibo_cai_utils;
import jibo = require('jibo');
import {Idle} from '../Idle';


/**
 * A state that handles reacting by playing a flow
 * @internal
 */
export class FlowState extends sm.State {

	private _flowHandle: any;
	private _flowPromise: Promise<any>;

	constructor(sm: sm.StateMachine, private idle: Idle, name: string, private flow: any, private blackboard?: any) {
		super(sm, name);
		this.onEntry = this._onEntry.bind(this);

		this.onStop = () => {
			if (this._flowHandle) {
				this._flowHandle.stop();
				this._flowHandle = null;
			}
		};

		this.onExit = () => {
			return this._flowPromise;
		};
	}

	_onEntry(trans: sm.Transition, input: any) {
		if (!this.flow) {
			this.idle.log.warn(`Skipping flow: '${this.name}'`);
		} else {
			this.idle.log.info(`Playing flow: '${this.name}'`);

			const result = {};
			const options = {
				result,
				blackboard: this.blackboard,
				assetPack: this.idle.assetPack,
				enableLogging: false,
			};

			const done = () => {
				this._flowHandle = null;
				this._flowPromise = null;
			};

			this._flowPromise = cu.PromiseUtils.promisify<any>(h => {
				this._flowHandle = jibo.flow.run(this.flow, options, h);
			})
			.then(done)
			.catch(e => {
				done();
				throw e;
			});
			return this._flowPromise.then(() => {
				return {
					result: result,
					lastResult: input
				};
			});
		}
	}
}
