import { libraries } from '@be/be-framework'; 
import cu = libraries.jibo_cai_utils;
export class Utils {
	/**
	 * Removes "Hey Jibo" or "Jibo" from the beginning of text.
	 * @param {string} input
	 * @return {string} The resulting text
	 */
	static cleanHJFromText(input: string): string {
		const lower = input.toLowerCase();
		let out: string;
		if (lower.startsWith('jibo')) {
			out = input.substr(4).trim();
		}	else if (lower.startsWith('hey jibo')) {
			out = input.substr(8).trim();
		} else {
			out = input;
		}
		return out;
	}

	/**
	 * Adds (or subtracts) a certain number of hours from a date
	 * @param {Date} refTime
	 * @param {number} hoursToAdd
	 */
	static addHoursToDate(refTime: Date, hoursToAdd: number): Date {
		return new Date(refTime.getTime() + cu.TimeUtils.hoursToMs(hoursToAdd));
	}

	/**
	 * Counts all times that happen earlier than a certain time
	 * @param {Date} refTime - Reference time
	 * @param {Date[]} times - All times to consider
	 */
	static countEarlierTimes(refTime: Date, times: Date[]): number {
		const refTimeNum = refTime.getTime();
		let count = 0;
		times.forEach(t => {
			const diff = t.getTime() - refTimeNum;
			if (diff > 0) {
				count++;
			}
		});
		return count;
	}
}

