import jibo = require('jibo');

import {CircadianManager} from './CircadianManager';
import {CircadianStateMachine} from './CircadianStateMachine';
import {CircadianState} from 'jibo-common-types';

let tunable = null;
try {
	tunable = require('jibo-tunable');
} catch(e) {
	// No tunable library found, disabling debug
}

const WIN_CIRC = 'Circadian'
export class TunableDebug {
	static setup (manager: CircadianManager) {
		if (tunable) {
			const T = tunable.Tunable;
			const sm = manager.circadianSM;

			T.getCheckboxField('Show Light Rings', false, WIN_CIRC).events.change.on(value => {
				manager.showDebuggingLightRings(value);
			});

			T.getDropdownField(`Set state`, Object.keys(CircadianState), 0, WIN_CIRC).events.change.on(value => {
				manager.setCircadianState(<CircadianState>value);
			});

			T.getDropdownField('Toggle Face Wakeup', ['ON', 'OFF'], 0, WIN_CIRC).events.change.on(value => {
				let toggle = (value === 'ON') ? true : false;
				manager.setFaceWakeup(toggle);
			})

			T.getDropdownField('Toggle Sound Wakeup', ['ON', 'OFF'], 0, WIN_CIRC).events.change.on(value => {
				let toggle = (value === 'ON') ? true : false;
				manager.setSoundWakeup(toggle);
			})

			T.getDropdownField('Wakeup logical', ['AND', 'OR'], 0, WIN_CIRC).events.change.on(value => {
				let toggle = (value === 'AND') ? true : false;
				manager.setWakeupFusion(toggle);
			})

			let fusionWindow = 10000;
			T.getNumberField('Wakeup fusion window (ms)', fusionWindow, 100, 60000, -1, WIN_CIRC).events.change.on(value => {
				manager.setFusionWindow(value);
			})

			let alertDuration = sm.getDuration(CircadianState.ALERT);
			T.getNumberField('ALERT duration', alertDuration, 1, 60, -1, WIN_CIRC).events.change.on(value => {
				alertDuration = Math.floor(value);
			});

			let relaxedDuration = sm.getDuration(CircadianState.RELAXED);
			T.getNumberField('RELAXED duration', relaxedDuration, 1, 360, -1, WIN_CIRC).events.change.on(value => {
				relaxedDuration = Math.floor(value);
			});

			let napDuration = sm.getDuration(CircadianState.DAYTIME_NAP);
			T.getNumberField('NAP duration', napDuration, 1, 240, -1, WIN_CIRC).events.change.on(value => {
				napDuration = Math.floor(value);
			});

			let fallingAsleepDuration = sm.getDuration(CircadianState.FALLING_ASLEEP);
			T.getNumberField('FALLING_ASLEEP duration', fallingAsleepDuration, 1, 60, -1, WIN_CIRC).events.change.on(value => {
				fallingAsleepDuration = Math.floor(value);
			});
			
			let wakingUpDuration = sm.getDuration(CircadianState.WAKING_UP);
			T.getNumberField('WAKING_UP duration', wakingUpDuration, 1, 360, -1, WIN_CIRC).events.change.on(value => {
				wakingUpDuration = Math.floor(value);
			});

			T.getButtonField('Change Durations', WIN_CIRC).events.change.on(() => {
				const durations = new Array<[CircadianState, number]>();
				durations.push([CircadianState.ALERT, alertDuration]);
				durations.push([CircadianState.RELAXED, relaxedDuration]);
				durations.push([CircadianState.DAYTIME_NAP, napDuration]);
				durations.push([CircadianState.FALLING_ASLEEP, fallingAsleepDuration]);
				durations.push([CircadianState.WAKING_UP, wakingUpDuration]);
				manager.restartStateMachineWithDurations(durations);
			});

			T.getButtonField('Reset Durations', WIN_CIRC).events.change.on(() => {
				const durations = new Array<[CircadianState, number]>();
				durations.push([CircadianState.ALERT, CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.get(CircadianState.ALERT)]);
				durations.push([CircadianState.RELAXED, CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.get(CircadianState.RELAXED)]);
				durations.push([CircadianState.DAYTIME_NAP, CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.get(CircadianState.DAYTIME_NAP)]);
				durations.push([CircadianState.FALLING_ASLEEP, CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.get(CircadianState.FALLING_ASLEEP)]);
				durations.push([CircadianState.WAKING_UP, CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.get(CircadianState.WAKING_UP)]);
				manager.restartStateMachineWithDurations(durations);
			});
		}
	}
}