import { Idle, LaunchOptions } from './Idle';

export { } // For Type definition purposes

const hjNoMatch = 'hjNomatch';
const goToSleep = 'sleep';
const turnAway = 'turnAway';
const turnAround = 'turnAround';

/**
 * @class SMEvents
 * @internal
 * @private
 * @extends {EventContainer}
 */
export class SMEvents extends te.EventContainer {
	nightStarts = new te.Event<any>('Nighttime starts');
	dayStarts = new te.Event<any>('Daytime starts');
	goToSleep = new te.Event<any>(`"Go to sleep"`);
	headTouch = new te.Event<any>('Head touch');
	noise = new te.Event<any>('Noise heard');
	faceAppeared = new te.Event<any>('Face appeared');
	hjHeard = new te.Event<any>('HJ Skill launch');
	plugStateChanged = new te.Event<any>('Plug state changed');
	screenTouched = new te.Event<any>('Screen touched');

	// Events just for debugging and presentation
	becomeAlert = new te.Event<any>('debug awake');
	becomeRelaxed = new te.Event<any>('debug relaxed');
	becomeAsleep = new te.Event<any>('debug asleep');
	becomeFallingAsleep = new te.Event<any>('debug fallingAsleep');
	becomeWakingUp = new te.Event<any>('debug wakingUp');
	becomeNap = new te.Event<any>('debug nap');
}

/**
 * The Entry state the splits either between the circadian state machine or an HJ no match.
 */
export class EntryState extends sm.State {
	private intentMap = new Map<string, sm.State>();
	private skill: Idle;

	constructor(private mainSM: CircadianStateMachine) {
		super(mainSM, CircadianState.SELECT_INTENT);
		this.mainSM.getCurrentState()
		this.skill = mainSM.parent.parent;
		this.onEntry = (trans, options?: LaunchOptions) => {
			this.skill.log.info(`Entering: ${this.name}`);
			options = options || {};
			Promise.all([
				this.resumeGlobalListen(),
				this.skill.forceEyeView()
			]).then(() => {
				// const intent = this.skill.getIntent(options);
				let intent = this.skill.getIntent(options);
				if (intent === hjNoMatch) {
					this.transitionTo(mainSM.hjNoMatch, options);
				} else if (intent === goToSleep) {
					this.transitionTo(mainSM.asleep);
				} else if (intent === turnAway || intent == turnAround) {
					this.transitionTo(mainSM.turnAway);
				} else {
					this.transitionTo(mainSM.alert);
				}
			}).catch(error => {
				this.skill.log.error('Error in forcing eye closed: ', error);
				this.transitionTo(mainSM.alert);
			})
		}
	}

	installTransitions() {
		this.addInternalTransition(CircadianState.ALERT, this.mainSM.alert);
		this.addInternalTransition(CircadianState.ASLEEP, this.mainSM.asleep);
		this.addInternalTransition(CircadianState.TURN_AWAY, this.mainSM.turnAway);
		this.addInternalTransition(hjNoMatch, this.mainSM.hjNoMatch);
	}

	private resumeGlobalListen(): Promise<void> {
		return jibo.jetstream.resetHotwordMode()
			.catch(e => {
				this.skill.log.warn('Error resuming global list: ', e);
			});
	}
}

/**
 * @class CircadianStateMachine
 * @internal
 * @private
 * @extends {StateMachine}
 */
export class CircadianStateMachine extends sm.StateMachine {

	// How far into the state we perform a musing
	BIG_MUSING_TIME_MS: number;
	SMALL_MUSING_TIME_MS: number;
	alert: AlertState;
	relaxed: RelaxedState; 
	nap: NapState;
	fallingAsleep: FallingAsleepState;
	entry = new EntryState(this);
	wakingUp: WakingUpState;
	events = new SMEvents();
	asleep = new AsleepState(this);
	checkToDState = new ChooseTimeState(this);
	turnAway = new TurnAwayState(this);
	hjNoMatch = new sm.State(this, CircadianState.HJ_NO_MATCH);

	static DEFAULT_CIRCADIAN_DURATIONS = new Map([
		[CircadianState.ALERT, 15],
		[CircadianState.RELAXED, 120],
		[CircadianState.DAYTIME_NAP, 30],
		[CircadianState.FALLING_ASLEEP, 15],
		[CircadianState.WAKING_UP, 30] // 645am to 715am
	]);

	private durations: Map<CircadianState, number>;
	
	constructor(public parent: CircadianManager, circadianDurations?: Array<[CircadianState, number]>) {
		super();

		this.durations = new Map(CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS);
		if (circadianDurations) {
			circadianDurations.forEach(([state, num]) => this.durations.set(state, num));
		}

		// Log durations
		this.parent.parent.log.debug('Circadian Durations: ');
		this.durations.forEach((value:number, key:CircadianState) => {
			this.parent.parent.log.debug(`${key} - ${value} mins`);
		});

		// init duration related fields once durations are set up
		this.BIG_MUSING_TIME_MS = cu.TimeUtils.minutesToMs(this.getDuration(CircadianState.ALERT) * 0.7); // play 70% through alert state
		this.SMALL_MUSING_TIME_MS = cu.TimeUtils.minutesToMs(this.getDuration(CircadianState.RELAXED) * 0.7); // play 70% through the relaxed state
		this.alert = new AlertState(this);
		this.relaxed = new RelaxedState(this);
		this.nap = new NapState(this);
		this.fallingAsleep = new FallingAsleepState(this);
		this.wakingUp = new WakingUpState(this);
	}

	init() {
		this.setInitial(this.entry);
		this.entry.installTransitions();

		const hjNoMatchSM = new HJNoMatch(this.parent.parent, new sm.StateMachine());
		this.hjNoMatch.onEntry = (trans, data) => {
			this.parent.pushAttentionMode(jibo.expression.AttentionMode.ENGAGED);
			return hjNoMatchSM.start(data);
		};

		this.hjNoMatch.onExit = (trans) => {
			return hjNoMatchSM.ensureStopped(); // make sure the state machine has stopped for when HJNoMatch is interrupted by global events.
		}

		this.hjNoMatch.addDoneTransition(this.entry);

		// Transitions
		this.checkToDState.installTransitions(this.relaxed, this.fallingAsleep);
		
		// timer-based transitions
		this.alert.installTransitions(this.checkToDState);
		this.relaxed.installTransitions(this.nap);
		this.nap.installTransitions(this.relaxed);
		this.fallingAsleep.installTransitions(this.asleep);
		this.wakingUp.installTransitions(this.relaxed);
		this.turnAway.installTransitions();
		
		// time-of-day transitions
		this.nap.addTypedEventTransition(this.events.nightStarts, this.fallingAsleep);
		this.relaxed.addTypedEventTransition(this.events.nightStarts, this.fallingAsleep);
		this.asleep.addTypedEventTransition(this.events.dayStarts, this.wakingUp);

		// sensory transitions
		this.nap.addTypedEventTransition(this.events.noise, this.relaxed);
		this.nap.addTypedEventTransition(this.events.faceAppeared, this.relaxed);
		this.wakingUp.addTypedEventTransition(this.events.noise, this.relaxed);
		this.wakingUp.addTypedEventTransition(this.events.faceAppeared, this.relaxed);

		// Global event transitions
		this.addGlobalTypedEventTransition(this.events.goToSleep, this.asleep);
		this.addGlobalTypedEventTransition(this.events.headTouch, this.alert);
		this.addGlobalTypedEventTransition(this.events.plugStateChanged, this.alert);
		this.addGlobalTypedEventTransition(this.events.screenTouched, this.alert);

		// TODO: just have to make sure that asleep is excluded.
		// that could be done by blocking the skill launch (event), rather than excluding the link??
		// or add the ability to exclude states from global transitions to the jibo-state-machine implementation
		this.addGlobalTypedEventTransition(this.events.hjHeard, this.alert);

		// global transitions for debugging and presentation purposes
		this.addGlobalTypedEventTransition(this.events.becomeAlert, this.alert);
		this.addGlobalTypedEventTransition(this.events.becomeRelaxed, this.relaxed);
		this.addGlobalTypedEventTransition(this.events.becomeNap, this.nap);
		this.addGlobalTypedEventTransition(this.events.becomeAsleep, this.asleep);
		this.addGlobalTypedEventTransition(this.events.becomeFallingAsleep, this.fallingAsleep);
		this.addGlobalTypedEventTransition(this.events.becomeWakingUp, this.wakingUp);

		// On every state transition we consider emitting a sleep change event
		this.stateChanged.on((transition: sm.Transition) => {
			this.parent.checkCircadianStateChange();
		});
	}

	/**
	 * Get the duration of the state
	 * @param {CircadianState} state whos duration should be returned 
	 * @return {number} duration of state or -1 if invalid 
	 */
	public getDuration(state: CircadianState): number {
		if (this.durations.has(state)) {
			const duration = this.durations.get(state);
			if (duration && duration >= 1) {
				return duration;
			} else {
				this.parent.parent.log.error(`Invalid duration of ${duration} for ${state}.`)
			}
		} else {
			this.parent.parent.log.error(`State is invalid ${state}.`);
		}

		if (CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.has(state)) {
			let defaultDuration = CircadianStateMachine.DEFAULT_CIRCADIAN_DURATIONS.get(state);
			this.parent.parent.log.warn(`Using default circadian duration of ${defaultDuration}.`);
			return defaultDuration;
		} else {
			this.parent.parent.log.error(`Default duration is invalid for state ${state}, returning 1 minute.`)
			return 1; // 1 minute. This should never happen.
		}
	}

	dispose() {
		this.destroy();
	}

	update() {
		super.update();
	}
}

// For unit testing purposes
if ((<any>global)._idleTest) {
	(<any>global)._idleTest.CircadianStateMachine = module.exports.CircadianStateMachine;
}
