/**
 * This state is for handling user-requests for privacy. Jibo will turn 180 degrees from his position when he enters this state (expected to be opposite the user).
 * After a short time jibo will ask if its alright that he turns around. 
 * @fileOverview
 *
 * Created on 12/14/17
 * @author James Staley <james.staley@jibo.com>
 */
import jibo = require('jibo');
import { CircadianState } from 'jibo-common-types';
import { Idle } from '../Idle';
import { Utils } from '../Utils';
import { BeSkill } from '@be/be-framework';
import { OTAUpdater } from './OTAUpdater';
import { CircadianStateMachine } from '../CircadianStateMachine';
import { libraries } from '@be/be-framework';
import cu = libraries.jibo_cai_utils;
import sm = libraries.jibo_state_machine;
import * as _ from 'lodash/lodash.min';

const path = require('path');
const TurnAwayFlow = require('../../flows/turnAway');
const AskToTurnBackMIM = "TurnBackQuestion";
const AnnounceTurnBackMIM = "TurnBackAnnouncement";

export class TurnAwayState extends sm.State {

	private skill: Idle;
	private flowHandle: any;
	private entryTime: number = -1; // class variable for testing purposes
	private MS_BEFORE_ASK = cu.TimeUtils.hoursToMs(1); // time until jibo asks if he can turn back around
	private MS_BEFORE_TURN = cu.TimeUtils.hoursToMs(6); // time until jibo will turn back around regardless of input

	//TODO: remove testing code - private MS_BEFORE_ASK = cu.TimeUtils.secondsToMs(10); // time until jibo asks if he can turn back around
	installTransitions() {
		this.addInternalTransition("Turning back", this.parent.relaxed);
		this.addInternalTransition("Deep sleep", this.parent.asleep);
	}

	constructor(private parent: CircadianStateMachine) {
		super(parent, CircadianState.TURN_AWAY);
		this.skill = parent.parent.parent;
		const manager = parent.parent;
		const expressor = manager.circadianExpression;

		let attentionHandle: jibo.expression.AttentionHandle;
		let hasAskedToTurnBack: boolean; // dont ask to turn back more than once
		let isTurningBack: boolean; // dont turn back after a long wait more than once

		this.onEntry = (transition) => {
			this.skill.log.info(`Entering ${this.name}`);
			this.entryTime = Date.now();
			attentionHandle = null;
			hasAskedToTurnBack = false;
			isTurningBack = false;

			manager.pushAttentionMode(jibo.expression.AttentionMode.OFF);
			expressor.queueAnimationsForTransition(transition);

			// track that we entered this state
			this.skill.track('Turned Away');
		};

		this.onUpdate = () => {
			const now = Date.now();
			if (!hasAskedToTurnBack && (now - this.entryTime > this.MS_BEFORE_ASK)) {
				hasAskedToTurnBack = true;
				this.askToTurnBack().then((intent) => {	
					if (intent === 'yes') {
						this.transitionTo(this.parent.relaxed);
					} else {
						this.skill.log.info(`Not turning around due to user intent ${intent}`);
					}
					this.skill.track('Turn Back', { user_response: (intent ? intent : 'UNDEFINED') });
				}).catch( (error) => {
					hasAskedToTurnBack = false; 
					this.skill.log.error('Failed to play turn back: ', error)
				});
			} else if (cu.TimeUtils.getPartOfDay(new Date()).basic === cu.PartOfDayBasic.NIGHT) { // check if we should go into deep sleep
				this.skill.log.info('Going into sleep state.');
				this.transitionTo(this.parent.asleep);
			} else if (!isTurningBack && now - this.entryTime > this.MS_BEFORE_TURN) { // check if we should turn around
				isTurningBack = true; 
				this.skill.log.info(`Attempting to turn back after long wait.`);
				this.announceTurnBack().then(() => {
					this.transitionTo(this.parent.relaxed);
				}).catch( (error) => {
					isTurningBack = false;
					this.skill.log.warn('Failed to turn back after long wait: ', error)
				});
			}
		};

		this.onStop = () => {
			this.cleanUp();
		}

		this.onExit = () => {
			this.cleanUp();
		}
	}

	/**
	 * Play a mim asking to turn back around and listen for the response
	 */
	private async askToTurnBack(): Promise<string | null> {
		const result = await this.playMIM(AskToTurnBackMIM);
		let intent;
		if (result) {
			intent = this.extractMIMResult(result);
		}
		return intent;
	}
	
	/**
	 * Announce that you're turning around
	 */
	private async announceTurnBack(): Promise<{}> {
		const prom = await this.playMIM(AnnounceTurnBackMIM);
		return prom;
	}
	
	private async playMIM(mim: string): Promise<{} | null> {
		const options = {
			assetPack: this.skill.assetPack,
			enableLogging: false,
			blackboard: {
				promptData: {},
				mimPath: path.join('mims', mim + '.mim'),
				result: {}
			},
		};
	
		try {
			await cu.PromiseUtils.promisify<any>(h => {
				this.flowHandle = jibo.flow.run(TurnAwayFlow, options, h);
			});
		} catch (e) {
			throw e;
		} finally {
			this.flowHandle = null;
		}
	
		return options.blackboard.result;
	}

	/**
	 * Clean up any conversation flow thats happening
	 */
	private cleanUp() {
		if (this.flowHandle) {
			this.flowHandle.stop();
			this.flowHandle = null;
		}
	}

	/**
	 * extracts whether a mimResult had a given intent
	 * @static
	 * @param mimResults
	 * @returns {string | null} either the string of the intent or a null indicating no intent
	*/
	private extractMIMResult(mimResult): string | null {
		return (mimResult) ? mimResult.asrResults.intent : null;
	}
}
