import jibo = require('jibo');
import {CircadianState} from 'jibo-common-types';
import { Idle } from '../Idle';
import { Utils } from '../Utils';
import { CircadianStateMachine } from '../CircadianStateMachine';
import { BeSkill, libraries } from '@be/be-framework';
import cu = libraries.jibo_cai_utils;
import sm = libraries.jibo_state_machine;
import * as _ from 'lodash/lodash.min';


export class AlertState extends sm.State {
	
	private timeoutState: sm.State;
	private duration = cu.TimeUtils.minutesToMs(this.parent.getDuration(CircadianState.ALERT));

	installTransitions(timeoutState: sm.State) {
		this.timeoutState = timeoutState;
		this.addInternalTransition(`Action Timeout of ${this.duration} ms.`, this.timeoutState);
	}

	constructor(private parent: CircadianStateMachine) {
		super(parent, CircadianState.ALERT);
		const skill = parent.parent.parent;
		const manager = parent.parent;
		const expressor = manager.circadianExpression;

		let hasMused = false;

		let startTime = -1;
		this.onEntry = (transition) => {
			skill.log.info(`Entering ${this.name}`);
			startTime = Date.now();
			
			hasMused = false;

			manager.pushAttentionMode(jibo.expression.AttentionMode.IDLE);
			expressor.queueAnimationsForTransition(transition);
		};

		this.onUpdate = () => {
			const now = Date.now();
			// If its time to play a big musing
			if ((now - startTime > parent.BIG_MUSING_TIME_MS) && !hasMused) {
				expressor.playBigMusing();
				hasMused = true;
			}
			if (now - startTime > this.duration) {
				this.transitionTo(this.timeoutState);
			}
		};
	}
}
