import jibo = require('jibo');
import Animation = jibo.animDB.Animation;
import AnimConfig = jibo.animDB.AnimConfig;
import Orientation = jibo.animDB.Orientation;
import * as _ from 'lodash/lodash.min';
import { libraries } from '@be/be-framework';
import { CircadianState } from 'jibo-common-types';
import te = libraries.jibo_typed_events;
import cu = libraries.jibo_cai_utils;
import { BeSkill, utils } from '@be/be-framework';
import { Options, AsyncCallback } from '@be/be-framework/lib/dts/BeSkill';
import { KBModel } from './KBModel';
import { CircadianManager } from './CircadianManager';

let tunable = null;
try {
    tunable = require('jibo-tunable');
} catch(e) {
    // No tunable library found, disabling debug
}

export interface LaunchOptions {
	nlu?: {
		intent?: string;
	};
	intent?: string;
	text?: string;
}

export class Idle extends BeSkill {

	static WINDOW_NAME = 'Idle';
	debug = utils.PackageUtils.debugMode('idle');
	public kbModel = new KBModel();
	private updateBinding = this.update.bind(this);
	private onTouchBind = this.onTouch.bind(this);
	private session: cu.SessionManager;
	private screenDofs: any;
	private circadianManager: CircadianManager;
	private closing = false;

	constructor(options?: Options) {
		super(options);

		this.circadianManager = new CircadianManager(this);

		const attemptErrorRecovery = (options: LaunchOptions): Promise<any> => {
			// Here we try to gracefully recover from the first error
			return cu.TimeUtils.wait(1000)
				.then(() => {
					this.circadianManager.resetCircadianStateMachine();
					return cu.TimeUtils.wait(1000);
				})
				.then(() => {
					this.session.replaceSession(options);
				});
		};

		const createSession = (options: LaunchOptions = {}): cu.Activity => {
			const promise = this.circadianManager.circadianSM.start(options)
				.catch(error => {
					if (!this.closing) {
						this.log.error(`Error in Idle (attempting recovery): `, error);
						return attemptErrorRecovery(options);
					} else {
						this.log.error(`Error in Idle while closing: `, error);
					}
				})
				.catch(error => {
					this.log.error(`Unrecoverable error in Idle: `, error);
				});

			return {
				promise,
				stop: () => {
					return this.circadianManager.circadianSM.stop()
						.catch(error => this.log.error('Could not stop circadian state machine: ', error));
				},
				update: () => this.circadianManager.update(),
			}
		};

		// We create the session manager
		this.session = new cu.SessionManager(
			createSession,
			() => { });
	}

	/**
	 * Called after the skill completes initialization (one time)
	 * @param {Function} done
	 */
	postInit(done: AsyncCallback) {
		// If the debug flag in package.json is set
		if (this.debug) {
			this.setupDebug();
		}

		this.screenDofs = jibo.expression.dofs.ALL.minus(jibo.expression.dofs.BODY).minus(jibo.expression.dofs.EYE_TRANSLATE).minus(jibo.expression.dofs.LED);

		this.kbModel.init()
			.then(() => done())
			.catch(e => {
				this.log.error(`error initializing kbModel: `, e);
				done(e);
			});
	}

	preload(done: (err?: any) => void) {

		// Subscribe our update method to jibo's timer
		jibo.timer.on('update', this.updateBinding);

		jibo.expression.setAttentionMode(jibo.expression.AttentionMode.IDLE)
			.then(() => done())
			.catch(done);
	}

	/**
	 * @override
	 * @param result
	 */
	open(result?: LaunchOptions, refresh?: boolean) {
		this.closing = false;
		jibo.mim.shouldShowGUI = false;
		jibo.mim.silentMenus = false;
		result = result || {};

		// make sure we subscribe to events whenever idle is launched but not refreshed.
		if (!refresh) {
			this.circadianManager.subscribeEventHandlers();
		}

		if (refresh || this.session.current) {
			this.session.replaceSession(result);
		} else {
			this.log.info('Starting');
			this.session.open(result);
		}
	}

	/**
	 * Skill launch options
	 * @param {LaunchOptions} [options] Skill launch options
	 */
	getIntent(options?: LaunchOptions): string {
		if (options) {
			return options.intent || (options.nlu ? options.nlu.intent : null);
		}
	}

	/**
	 * Called on every timer tick when in skill
	 */
	update() {
		// Update state machine
		if (this.session.current) {
			this.session.current.update();
		}
	}

	/**
	 * Forces a touch handler on the eye that launches into the main menu
	 */
	async forceEyeView(): Promise<any> {
		// Temporarily using "Test" dof arbiter name which gets very high priority
		// we are doing this in order to guarantee a very clean screen upon entry into idle
		await jibo.expression.cleanup({
			requestor: 'Test',
			dofs: this.screenDofs
		});

		// Wait for the eye view to be forced closed
		const forceEyeviewPr = new Promise<any>((resolve, reject) => {
			jibo.face.views.forceEyeView(resolve, this.onTouchBind, jibo.face.views.IN, jibo.face.views.UP, reject);
		}).catch(e => {
			this.log.warn(`Error while in 'forceEyeView': `, e);
		});

		await Promise.race([
			cu.TimeUtils.wait(5000),
			forceEyeviewPr,
		]);
	}

	/**
	 * Called when jibo's screen is touched
	 */
	onTouch(): void {
		// if we're already in ALERT or RELAXED, just show the menu.
		if (this.circadianManager.getCurrentCircadianState() === CircadianState.ALERT ||
			this.circadianManager.getCurrentCircadianState() === CircadianState.RELAXED) {
			this.redirect('@be/main-menu', { intent: 'tap' });
		} else {
			this.circadianManager.screenWasTouched();
		}
	}

	/**
	 * Called when the skill closes
	 * @param {Function} done
	 */
	close(done: (err?: any) => void): void {
		this.closing = true;
		this.log.info('Stopping');

		const cleanUp = (err?: any) => {
			// before closing, remove the actions you placed on the eye view
			if (jibo.face.views.currentView) {
				jibo.face.views.currentView.clearActions();
			}

			// Unsubscribe our update method from jibo's timer
			jibo.timer.removeListener('update', this.updateBinding);

			// unsubscribe from other events we're listening to
			this.circadianManager.unsubscribeEventHandlers();

			// clear the animation queue
			this.circadianManager.circadianExpression.clearAnimationQueue();

			// release the last attention mode
			this.circadianManager.clearAttentionMode();

			done(err);
		};

		const closingPromises = [this.session.close()]
		
		// If we have a dim screen, restore the original brightness (only run on robot to prevent test failures)
		if ((jibo.runMode === jibo.RunMode.ON_ROBOT) && !this.circadianManager.currentlyAwake()) {
			closingPromises.push(this.circadianManager.circadianExpression.restoreScreenBrightness());
		}

		cu.PromiseUtils.timeout(Promise.all(closingPromises), 1000)
			.then(() => cleanUp())
			.catch(cleanUp);
	}

	/**
	 * Sets up various Tunable debug utilities for the skill
	 */
	private setupDebug() {
		if (tunable) {
			const T = tunable.Tunable;
			T.getButtonField('Clear KBModel', Idle.WINDOW_NAME)
				.events.change.on(() => this.kbModel.clear());
		}
	}

	/**
	 * Wrapper to replace the current idle session with no options.
	 * Only to be used when reconfiguring the circadian state machine for tuning.
	 */
	public replaceSession() {
		this.log.warn('Replacing session, this should never be called in production.');
		this.session.replaceSession({});
	}
}
