import { libraries } from '@be/be-framework';
import { CircadianManager } from './CircadianManager';

export interface CancelableElement {
	promiseGenerator: () => Promise<any>;
	cancel: () => void;
	cancelWhenNewAdded?: boolean;
}

export class CancelableQueue {
	prQueue = new libraries.jibo_cai_utils.PromiseQueue();
	current: CancelableElement = null;

	add(element: CancelableElement) {
		if (this.current && this.current.cancelWhenNewAdded) {
			this.current.cancel();
		}
		this.prQueue.add(async () => {
			this.current = element;
			try {
				await this.current.promiseGenerator()
			} finally {
				this.current = null;
			}
		});
	}

	waitUntilEmpty() {
		this.prQueue.waitUntilEmpty().catch(error => {
			console.error('CancelableQueue', error);
		});
	}

	clear() {
		this.prQueue.clear();
		if (this.current) {
			this.current.cancel();
		}
		this.current = null;
	}

	stop() {
		this.clear();
	}
}