import jibo = require('jibo');
import { libraries } from '@be/be-framework';
export import sm = libraries.jibo_state_machine;
import { FlowState } from '../states/FlowState';
import { Idle, LaunchOptions } from '../Idle';
import { Utils } from '../Utils';

let tunable;
try {
    tunable = require('jibo-tunable');
} catch(e) {
    // No tunable library found, disabling debug
}

// Require all the flows which ensures they get browserified
const Flows = {
	Blink: require('../../flows/global/blink'),
	Confused: require('../../flows/nomatch/confused-nomatch'),
	Glances: require('../../flows/nomatch/glances-nomatch'),
	Reset: require('../../flows/nomatch/reset-nomatch'),
	Thinking: require('../../flows/nomatch/thinking-nomatch'),
	Verbal: require('../../flows/nomatch/verbal-nomatch'),
};

enum DebugMode {
	Disabled = <any> 'Disabled',
	ForceVerbal = <any> 'ForceVerbal',
	ForceNonVerbal = <any> 'ForceNonVerbal',
}

export class HJNoMatch {

	initState = new sm.State(this.statemachine, 'Start');
	doneState = new sm.State(this.statemachine, 'Done');

	thinkingState = new FlowState(this.statemachine, this.parent, 'Thinking animation', Flows.Thinking);
	confusedState = new FlowState(this.statemachine, this.parent, 'Confused animation', Flows.Confused);
	glancesState = new FlowState(this.statemachine, this.parent, 'Glances animation', Flows.Glances);
	blinkState = new FlowState(this.statemachine, this.parent, 'Blink animation', Flows.Blink);
	resetState = new FlowState(this.statemachine, this.parent, 'Reset animation', Flows.Reset);

	shouldDoVerbalState = new sm.State(this.statemachine, 'Should we do verbal response?');
	doVerbalState = new FlowState(this.statemachine, this.parent, 'Do verbal response', Flows.Verbal);

	showTextState = new sm.State(this.statemachine, 'Show text on screen');
	removeTextState = new sm.State(this.statemachine, 'Remove text');

	private debugMode = DebugMode.Disabled;

	constructor(public parent: Idle, private statemachine: sm.StateMachine) {
		// Set up tunable debug interface for triggering fun parent
		if (this.parent.debug && tunable) {
			const T = tunable.Tunable;
			T.getButtonField('HJNoMatch: Trigger', Idle.WINDOW_NAME)
				.events.change.on( () => jibo.globalEvents.shared.noGlobalMatch.emit({
					status: jibo.jetstream.types.TurnResultType.SUCCEEDED,
					result: new jibo.jetstream.types.ListenResult(
						{
							text: "hey jibo some text",
							confidence: 1
						},
						null
					),
					global: true
				}) );

			T.getDropdownField('HJNoMatch: Override Verbal', Object.keys(DebugMode), 0, Idle.WINDOW_NAME)
				.events.change.on( option => this.debugMode = DebugMode[<string>option]);
		}

		let attentionHandle: jibo.expression.AttentionHandle;
		this.initState.onEntry = async (trans, data) => {
			this.parent.log.info(`HJ NoMatch entering`);
			return data; // Pass initial data forward
		};

		this.doneState.onEntry = async () => {
			this.parent.log.info('HJ NoMatch exiting');
			return this.stop();
		};

		let shouldDoVerbal = false;
		// Create show state and remove state
		this.showTextState.onEntry = (trans: sm.Transition, data: any) => {
			return this.shouldDoVerbal().then(should => {
				shouldDoVerbal = should;

				let text: string;
				if (typeof data === 'string') {
					text = data;
				} else if (data && data.lastResult && (typeof data.lastResult.text === 'string')) {
					text = data.lastResult.text;
				}

				if (!text) {
					this.parent.log.warn('No HJNomatch text found');
					text = "";
				}

				text = Utils.cleanHJFromText(text);

				// do analytics even logging here
				//NOTE: Raw ASR text leaving robot here!
				this.parent.track('Idle No Match', {text}); // if we wanna put more data here, we can. Spec still under discussion.

				// This change represents a design decision to never to top label and no quotes
				// this.showText(`"${data.lastResult}"`, !shouldDoVerbal);
				this.showText(`"${text}"`, false);
			});
		};
		this.removeTextState.onEntry = () => {
			return this.parent.forceEyeView();
		};

		this.shouldDoVerbalState.onEntry = () => {
			if (shouldDoVerbal) {
				this.parent.log.info(`HJ NoMatch performing verbal prompt`);
				this.shouldDoVerbalState.transitionTo(this.doVerbalState);
			} else {
				this.parent.log.info(`HJ NoMatch performing non-verbal prompt`);
				this.shouldDoVerbalState.transitionTo(this.confusedState);
			}
		};

		this.initState.addDoneTransition(this.thinkingState);

		this.thinkingState.addDoneTransition(this.showTextState);
		this.showTextState.addDoneTransition(this.shouldDoVerbalState);

		this.confusedState.addDoneTransition(this.removeTextState);
		this.shouldDoVerbalState.addInternalTransition('Yes', this.doVerbalState);
		this.shouldDoVerbalState.addInternalTransition('No', this.confusedState);
		this.doVerbalState.addDoneTransition(this.removeTextState);

		this.removeTextState.addDoneTransition(this.glancesState);
		this.glancesState.addDoneTransition(this.blinkState);
		this.blinkState.addDoneTransition(this.resetState);
		this.resetState.addDoneTransition(this.doneState);
	}

	public start(options?: LaunchOptions): Promise<void> {
		return this.statemachine.start(options);
	}

	public stop(): Promise<void> {
		return this.statemachine.stop();
	}

	public async ensureStopped(): Promise<void> {
		if (this.statemachine.isRunning) {
			this.parent.log.info('Stopping HJNoMatch state machine due to interruption.');
			return this.stop();
		}
	}

	/**
	 * Determines whether we should do a verbal greeting, based on recency of
	 * previous verbal greetings to this user
	 * @return {boolean}
	 */
	async shouldDoVerbal(): Promise<boolean> {
		const person = jibo.lps.identity.getActiveSpeaker();
		const personId = person ? person.idInfo.id : null;
		let shouldBeVerbal: boolean;
		// If we are not in debug mode
		if (this.debugMode === DebugMode.Disabled) {
			// If a person is identified
			if (person) {
				// We get all the verbal no-matches for this person
				const verbalNoMatchTimes = await this.parent.kbModel.getVerbalNoMatches(personId);
				// If they have heard it 10 times or more, we stop
				if (verbalNoMatchTimes.length >= 10) {
					shouldBeVerbal = false;
				} else {
					// We count how many times they've heard it in the last 24 hours
					const refTime = Utils.addHoursToDate(new Date(), -24);
					const recentVerbal = Utils.countEarlierTimes(refTime, verbalNoMatchTimes);
					shouldBeVerbal = recentVerbal < 4;
				}
			} else {
				// We count how many unidentified verbal greetings have been delivered in the last hour
				const verbalNoMatchTimes = await this.parent.kbModel.getVerbalNoMatches();
				const refTime = Utils.addHoursToDate(new Date(), -1);
				const recentVerbal = Utils.countEarlierTimes(refTime, verbalNoMatchTimes);
				shouldBeVerbal = recentVerbal < 3;
			}
		} else {
			// We use the debug mode
			shouldBeVerbal = (this.debugMode === DebugMode.ForceVerbal);
		}

		if (shouldBeVerbal) {
			await this.parent.kbModel.markVerbalNoMatch(new Date(), personId);
		}
		return shouldBeVerbal;
	}

	/**
	 * Displays text on screen
	 * @param {string} text - Text to put on screen
	 * @param {boolean} showHeader - Whether to add top header label
	 */
	showText(text: string, showHeader: boolean) {
		const FaceRenderer: any = (<any>jibo).FaceRenderer;

		const componentConfigs = [];

		if (showHeader) {
			componentConfigs.push({
				id: "top",
				type: "Label",
				text: "This Confused me",
				style: {
					fontSize: "50",
					fontFamily: "Proxima Nova Soft",
					fontStyle: "bold",
					fill: "#FFFFFF", // Temporary orange color
					wordWrap: true,
					wordWrapWidth: 1240,
					align: 'center'
				},
				position: {
					x: FaceRenderer.WIDTH / 2,
					y: 100
				},
				targetAnchor: {
					x: 0.5,
					y: 0.5
				}
			});
		}

		componentConfigs.push({
			id: "bottom",
			type: "Label",
			text: text,
			style: {
				fontSize: "120",
				fontFamily: "Proxima Nova Soft",
				fontStyle: "bold",
				fill: "#b6b6c2",
				wordWrap: true,
				wordWrapWidth: 1240,
				align: 'center'
			},
			position: {
				x: FaceRenderer.WIDTH / 2,
				y: FaceRenderer.HEIGHT / 2
			},
			targetAnchor: {
				x: 0.5,
				y: 0.5
			}
		});


		const viewConfig = {
			componentConfigs,
			viewConfig: {
				type: "View",
				id: "global_not_matched_text"
			},
		};

		// Here we queue up screen content and clears
		jibo.face.views.createView("View", viewConfig, true);
	}

	/**
	 * Is the passed in state one on the HJ No Match path?
	 */
	containsState(state: sm.State): boolean {
		return (state === this.initState || state === this.doneState ||
				state === this.thinkingState || state === this.confusedState ||
				state === this.glancesState || state === this.blinkState ||
				state === this.resetState || state === this.shouldDoVerbalState ||
				state === this.doVerbalState || state === this.showTextState ||
				state === this.removeTextState);
	}
}
