import jibo = require('jibo');
import { CircadianState } from 'jibo-common-types';
import { Idle } from '../Idle';
import { Utils } from '../Utils';
import { BeSkill } from '@be/be-framework';
import { OTAUpdater } from './OTAUpdater';
import { CircadianStateMachine } from '../CircadianStateMachine';
import { libraries } from '@be/be-framework';
import cu = libraries.jibo_cai_utils;
import sm = libraries.jibo_state_machine;
import * as _ from 'lodash/lodash.min';
import { Transition } from '../../../../../packages/jibo-state-machine/dts/index';

// TODO: Turn off screen when fully asleep
export class AsleepState extends sm.State {

	private updater: OTAUpdater;
	private skill: Idle;
	constructor(private parent: CircadianStateMachine) {
		super(parent, CircadianState.ASLEEP);
		this.skill = parent.parent.parent;
		const manager = parent.parent;
		const expressor = manager.circadianExpression;

		this.updater = new OTAUpdater(this.skill);

		let attentionHandle: jibo.expression.AttentionHandle;
		let entryTime = -1;

		this.onEntry = (transition) => {
			this.skill.log.info(`Entering ${this.name}`);
			entryTime = Date.now();
			this.updater.checkForUpdates();
			attentionHandle = null;

			manager.pushAttentionMode(jibo.expression.AttentionMode.OFF);
			expressor.queueAnimationsForTransition(transition);
		};

		this.onUpdate = () => {
			this.updater.update(Date.now() - entryTime);
		};

		this.onExit = (transition) => {
			if (transition.name) {
				this.trackReasonForWakeup(transition.name);
			}
		}
	}

	/**
	 * Track a domo event explaining why we woke up.
	 * @param {string} transitionName that caused us to wake up.
	 */
	private trackReasonForWakeup(transitionName: string) {
		let reason = 'unknown';
		if (transitionName === "TEvent: " + this.parent.events.headTouch.name) {
			reason = 'head_touched';
		} else if (transitionName === "TEvent: " + this.parent.events.screenTouched.name) {
			reason = 'screen_touched';
		} else if (transitionName === "TEvent: " + this.parent.events.hjHeard.name) {
			reason = 'hj_heard';
		} else if (transitionName === "TEvent: " + this.parent.events.dayStarts.name) {
			reason = 'day_started';
		} else {
			this.skill.log.warn(`Unknown wake reason for analytics: ${transitionName}`);
			reason = transitionName;
		}

		this.skill.track('Wake Method', { eventType: reason });
	}
}
