import jibo = require('jibo');
import Animation = jibo.animDB.Animation;
import AnimConfig = jibo.animDB.AnimConfig;
import AttentionMode = jibo.expression.AttentionMode;
import AttentionHandle = jibo.expression.AttentionHandle;
import { CircadianState } from 'jibo-common-types';
import Orientation = jibo.animDB.Orientation;
import { Utils } from './Utils';
import { Idle } from './Idle';
import { CircadianStateMachine } from './CircadianStateMachine';
import { CircadianExpression } from './CircadianExpression';
import { TunableDebug } from './TunableDebug';
import { BeSkill, libraries } from '@be/be-framework';
import cu = libraries.jibo_cai_utils;
import SpikeData = cu.SpikeData;
import * as _ from 'lodash/lodash.min';

export { } // For Type definition purposes

/**
 * Color definitions for circadian states. Used only to debug circadian stuff.
 */
const ALERT_LED_COLOR = [1, 0, 0];
const RELAXED_LED_COLOR = [0.1, 0.4, 0.2];
const DAYTIME_NAP_LED_COLOR = [0.1, 0.1, 0.5];
const ASLEEP_LED_COLOR = [0.5, .1, 1.0];
const WAKING_UP_LED_COLOR = [0.5, 0.5, 0];
const FALLING_ASLEEP_LED_COLOR = [0.8, 0.5, 0.8];
const HJ_NO_MATCH_COLOR = [0.3, 0.5, 0.9];

// How far above the baseline (in stdDev) does a sound need to be to wake Jibo up without an accompanying face
const SOUND_WAKE_UP_DEVIATION = 2.5;

// What sounds will wake up jibo regardless of deviation or baseline˝
const ABSOLUTE_WAKE_SOUND_LEVEL = -30;

// Allow snuggles at this period
const SNUGGLE_INTERVAL = cu.TimeUtils.secondsToMs(1.0); // top ten variable names of all time.

/**
 * @internal
 * @private
 */
export class CircadianManager {
	public currentPoD: cu.PartOfDay = null;

	// Animation
	public circadianExpression = new CircadianExpression(this);
	private lastCircadianState: CircadianState = null;
	private goToSleepHandlerBind = () => this.goToSleepHandler();
	private headTouchHandlerBind = (data) => this.headTouchHandler(data);
	private noiseHandlerBind = (data: SpikeData) => this.noiseHandler(data);
	private faceHandlerBind = () => this.faceHandler();
	private heyJiboHandlerBind = () => this.heyJiboHandler();
	private plugStateChangedBind = () => this.plugStateChanged();

	// Wake-up fusion
	private wakeWithSound: boolean = true;
	private wakeWithFace: boolean = true;
	private wakeEventFusion: boolean = true;
	private waitingForSound: boolean = false;
	private waitingforFace: boolean = false;
	private wakeFusionTime: number = null;
	private fusionWindowMs: number = 10000; // the length of the fusion window in ms
	private useLEDForDebug: boolean = false;

	// Reindexing
	private lastReIndexTime = -1;
	private nextReIndexTime = -1;

	// snuggling
	private lastSnuggleTime = -1;

	// attention
	private attentionHandle: jibo.expression.AttentionHandle = null;
	private atnModeQueue = new libraries.jibo_cai_utils.PromiseQueue();

	// Debugging 
	private circadianColorMap: Map<CircadianState, number[]> = new Map([
		[CircadianState.ALERT, ALERT_LED_COLOR],
		[CircadianState.RELAXED, RELAXED_LED_COLOR],
		[CircadianState.DAYTIME_NAP, DAYTIME_NAP_LED_COLOR],
		[CircadianState.ASLEEP, ASLEEP_LED_COLOR],
		[CircadianState.WAKING_UP, WAKING_UP_LED_COLOR],
		[CircadianState.FALLING_ASLEEP, FALLING_ASLEEP_LED_COLOR],
		[CircadianState.HJ_NO_MATCH, HJ_NO_MATCH_COLOR]
	]);

	public circadianSM = new CircadianStateMachine(this);

	constructor(public parent: Idle) {
		// order matters here, circadian animation must exist for the state machine to set up
		this.circadianSM.init();

		TunableDebug.setup(this);
	}

	/**
	 * Reset the circadian state machine. For error recovery at the Idle level.
	 */
	resetCircadianStateMachine(circadianDurations?: Array<[CircadianState, number]>) {
		this.circadianSM.destroy().catch(error => this.parent.log.error('Could not destory state machine: ', error));
		this.circadianSM = new CircadianStateMachine(this, circadianDurations);
		this.circadianSM.init();
	}

	checkCircadianStateChange() {
		const current = this.getCurrentCircadianState();
		if (current && current !== this.lastCircadianState) {
			this.parent.log.info(`State changed from ${this.lastCircadianState} to ${current}.`);
			jibo.performance.log("State Changed", `${this.lastCircadianState} to ${current}`);
			this.lastCircadianState = current;

			// Don't inform our parent or change lights for circadian state with immediate transitions
			if (!this.isInternalState(current)) {
				// inform the action system of the change
				jibo.action.setCurrentCircadianState(current);

				if (this.useLEDForDebug) {
					// Change the light-ring in correspondence with circadian state
					const color = this.circadianColorMap.get(current);
					color && jibo.expression.setLEDColor([color[0], color[1], color[2]]);
				}
			}
		}
	}

	getCurrentCircadianState(): CircadianState | null { // EntryState results in null
		const current = this.circadianSM.getCurrentState();
		const circadianState = CircadianState[current.name];

		if (!circadianState) {
			// Special case to encapsulate all the HJ states into one circadian state
			if (current === this.circadianSM.hjNoMatch) {
				return CircadianState.HJ_NO_MATCH;
			} else {
				this.parent.log.warn(`Unrecognized circadian state ${current.name}`);
			}
		}

		return circadianState;
	}

	/**
	 * Check whether the current circadian state is an awake state. RELAXED and AWAKE are the awake states as of writing.
	 * @return {bool} indicating whether jibo appears to be awake
	 */
	currentlyAwake() {
		let awake = false;

		const state = this.circadianSM.getCurrentState();
		if (state) {
			const circadianState = CircadianState[state.name];
			awake = (circadianState === CircadianState.ALERT || circadianState === CircadianState.RELAXED);
		}
		return awake;
	}

	/**
	 * Set a new attention mode and clear out the old one.
	 * @param {AttentionHandle} attentionMode to switch to.
	 */
	pushAttentionMode(attentionMode: jibo.expression.AttentionMode) {
		this.atnModeQueue.add(async () => {
			// Release the old attention mode
			if (this.attentionHandle) {
				try {
					await this.attentionHandle.release();
				} catch (error) {
					this.parent.log.error(`Failed to release attention handle while pushing mode:${attentionMode} with error: `, error);
				}
			}

			try {
				this.attentionHandle = await jibo.expression.pushAttentionMode(attentionMode);
			} catch (error) {
				this.parent.log.error(`Failed to push new attention mode: ${attentionMode} with error: `, error);
			}
		});
	}

	/**
	 * Release the attention mode.
	 */
	clearAttentionMode() {
		if (this.attentionHandle) {
			this.attentionHandle.release()
				.catch(error => this.parent.log.error('Attention handle release failed: ', error));
			this.attentionHandle = null;
		}
	}

	update() {
		const now = new Date();
		const newToD = cu.TimeUtils.getPartOfDay(now);
		if (!_.isEqual(newToD, this.currentPoD)) {
			this.currentPoD = newToD;
			if (this.currentPoD.basic === cu.PartOfDayBasic.MORNING && this.currentPoD.detail === cu.PartOfDayDetail.MID) {
				this.circadianSM.events.dayStarts.emit();
			} else if (this.currentPoD.basic === cu.PartOfDayBasic.NIGHT && this.currentPoD.detail === cu.PartOfDayDetail.EARLY) {
				this.circadianSM.events.nightStarts.emit();
			}
		}
		this.circadianSM.update();
	}

	/**
	 * Get into a position where we can show the menu.
	 */
	screenWasTouched() {
		this.circadianSM.events.screenTouched.emit();
	}

	/**
	 * Handler for global go to sleep calls
	 */
	goToSleepHandler() {
		this.circadianSM.events.goToSleep.emit();
	}

	/**
	 * Handle head touches
	 * @param data about head touch event
	 */
	headTouchHandler(data: boolean[]) { // TODO: get access to HeadTouchData
		this.parent.log.debug("headTouchHandler");
		const now = Date.now();

		// Don't emit a snuggle (headpat) event until we change state. This will only keep on head pat from emitting a snuggle.
		// Don't emit snuggle events too frequently
		if (this.getCurrentCircadianState() !== CircadianState.ALERT) {
			this.circadianSM.events.headTouch.emit();
		} else if (this.lastSnuggleTime === -1 || (now - this.lastSnuggleTime) > SNUGGLE_INTERVAL) {
			this.lastSnuggleTime = now;

			// This clear animation queue is here (instead of CircadianExpression) because we want to clear the queue when we're going to
			//  to a snuggle animation, but NOT when we're waking up from a head touch (or we wont play the wake-up animations).
			this.parent.log.info("Clearing animation queue due to snuggle.");
			this.circadianExpression.clearAnimationQueue();

			const query = jibo.emotion.reactToHeadTouch(data); // trigger emotion changes and get back the animation to play
			if (query) {
				this.circadianExpression.playAnimDBAnimation({query: query});
			} else {
				this.parent.log.warn("No animation given by head touch.");
			}
		} else {
			this.parent.log.info(`Ignoring snuggle events due to frequency. Can't snuggle more than once every ${SNUGGLE_INTERVAL}ms.`);
		}
	}

	/**
	 * Handler for noise events
	 * A very loud noise will wake up jibo without his seeing a face.
	 * A quieter, but still loud noise will wake up jibo if he also sees a face.
	 */
	noiseHandler(data: SpikeData) {
		const state = this.getCurrentCircadianState();
		if (state !== CircadianState.WAKING_UP && state !== CircadianState.DAYTIME_NAP) {
			return;
		}

		let emit = false;
		if (this.wakeWithSound) {
			this.parent.log.debug("noise handler");
			// first check whether the deviation is loud enough taht we should emit regardless of the rules
			if (data.recentDeviationFromBaseline > SOUND_WAKE_UP_DEVIATION || data.recentMean > ABSOLUTE_WAKE_SOUND_LEVEL) {
				this.parent.log.debug(`Extreme Sound event. baseline-mean/stdev: ${data.baselineMean.toFixed(2)} / ${data.baselineStdDev.toFixed(2)} recentMean: ${data.recentMean.toFixed(2)} deviation:${data.recentDeviationFromBaseline}.`);
				emit = true;
			} else if (this.wakeEventFusion) {
				this.fuseWakeUpEvents(false, true);
			} else {
				emit = true;
			}
		}

		if (emit) {
			this.circadianSM.events.noise.emit();
		}
	}

	/**
	 * handler for faces seen
	 */
	faceHandler() {
		if (this.wakeWithFace) {
			this.parent.log.debug("face handler");
			if (this.wakeEventFusion) {
				this.fuseWakeUpEvents(true, false);
			} else {
				this.circadianSM.events.faceAppeared.emit();
			}
		}
	}

	/**
	 * handler for HJs
	 */
	heyJiboHandler() {
		this.parent.log.debug("heyJiboHandler");
		this.circadianSM.events.hjHeard.emit();
	}

	/**
	 * Handler for when the plug state changes
	 */
	plugStateChanged() {
		this.parent.log.debug("plugStateChangedHandler");
		this.circadianSM.events.plugStateChanged.emit();
	}

	/**
	 * Subscribe to circadian relevant events
	 */
	subscribeEventHandlers() {
		jibo.lps.detector.ambientAudioSpike.trigger.on(this.noiseHandlerBind);

		jibo.jetstream.events.hjHeard.on(this.heyJiboHandlerBind);

		jibo.lps.identity.events.visibleFaceStarted.on(this.faceHandlerBind);

		jibo.globalEvents.sleep.on(this.goToSleepHandlerBind);
		jibo.action.events.secondHandTouchStop.on(this.headTouchHandlerBind);

		jibo.system.events.pluggedIn.on(this.plugStateChangedBind);
		jibo.system.events.unplugged.on(this.plugStateChangedBind);

		// Note: we don't need a skill launch event since it will always send jibo OUT of idle, and when
		//  he returns to idle he should be in ACTIVE.
	}

	/**
	 * Unsubscribe from circadian relevant events.
	 */
	unsubscribeEventHandlers() {
		jibo.lps.detector.ambientAudioSpike.trigger.removeListener(this.noiseHandlerBind);

		jibo.jetstream.events.hjHeard.removeListener(this.heyJiboHandlerBind);

		jibo.lps.identity.events.visibleFaceStarted.removeListener(this.faceHandlerBind);

		jibo.globalEvents.sleep.removeListener(this.goToSleepHandlerBind);
		jibo.action.events.secondHandTouchStop.removeListener(this.headTouchHandlerBind);

		jibo.system.events.pluggedIn.removeListener(this.plugStateChangedBind);
		jibo.system.events.unplugged.removeListener(this.plugStateChangedBind);
	}

	/**
	 * Fuse face and noise events so a nap wake-up only occurs when both events happen within a window.
	 * TODO: rewrite this in a way that makes it even remotely intelligible. Should be modified to take an array of booleans associated times. Emit when all bools are true.
	 * @param {boolean} face a face event triggered this check
	 * @param {boolean} noise a noise event triggered this check
	 */
	private fuseWakeUpEvents(face: boolean, noise: boolean) {
		const now = Date.now();
		const errorMessage = 'Unexpected case in fuseWakeUpEvents at point: ';
		let emitEventAndReset = false;
		if (this.wakeFusionTime && (now - this.wakeFusionTime) <= this.fusionWindowMs) { // we're currently waiting for the opposite event to the one that started the timer
			if (this.waitingforFace) {
				if (noise) {
					this.parent.log.debug(`Heard sound, waiting for ${this.fusionWindowMs}ms to see face.`)
					this.wakeFusionTime = now; // reset timer
				} else if (face) {
					emitEventAndReset = true; // this is what we were waiting for
				} else {
					this.parent.log.error(errorMessage, 'waiting for face.');
				}
			} else if (this.waitingForSound) {
				if (noise) {
					emitEventAndReset = true; // this is what we're waiting for
				} else if (face) {
					this.parent.log.debug(`Saw face, waiting for ${this.fusionWindowMs}ms to hear sound.`)
					this.wakeFusionTime = now; // reset timer
				} else {
					this.parent.log.error(errorMessage, 'waiting for sound.');
				}
			} else {
				this.parent.log.error(errorMessage, 'nonsensically waiting for fusion.');
			}
		} else {
			// We're not waiting for anything or the window expired
			this.waitingforFace = false;
			this.waitingForSound = false;
			this.wakeFusionTime = now;
			if (face) {
				this.waitingForSound = true;
				this.parent.log.debug(`Saw face, waiting for ${this.fusionWindowMs}ms to hear sound.`)
			} else if (noise) {
				this.waitingforFace = true;
				this.parent.log.debug(`Heard sound, waiting for ${this.fusionWindowMs}ms to see face.`)
			} else {
				this.parent.log.error(errorMessage, 'fusion window opened for unknown cause.');
			}
		}

		if (emitEventAndReset) {
			this.parent.log.info("Triggering wakeup. Got both required events.");
			this.wakeFusionTime = null;
			this.waitingforFace = false;
			this.waitingForSound = false;
			this.circadianSM.events.faceAppeared.emit();
		}
	}

	/**
	 * Determine whether a state for circadian's internal use
	 */
	private isInternalState(state: CircadianState): boolean {
		return (state === CircadianState.TIME_OF_DAY ||
			state === CircadianState.SELECT_INTENT);
	}

	// Tunable Methods
	//  methods for debugging/tuning. Should not be invoked for any other purpose

	/**
	 * Force the circadian state to change
	 * @param {CircadianState} transition into this state
	 * @intdocs
	 */
	setCircadianState(state: CircadianState) {
		switch (state) {
			case CircadianState.ALERT:
				this.circadianSM.events.becomeAlert.emit();
				break;
			case CircadianState.RELAXED:
				this.circadianSM.events.becomeRelaxed.emit();
				break;
			case CircadianState.WAKING_UP:
				this.circadianSM.events.becomeWakingUp.emit();
				break;
			case CircadianState.DAYTIME_NAP:
				this.circadianSM.events.becomeNap.emit();
				break;
			case CircadianState.FALLING_ASLEEP:
				this.circadianSM.events.becomeFallingAsleep.emit();
				break;
			case CircadianState.ASLEEP:
				this.circadianSM.events.becomeAsleep.emit();
				break;
			default:
				this.parent.log.warn(`Set circadian state called with unrecognized state ${state}`);
		}
	}


	/**
	 * Toggle whether seeing a face will wake jibo up
	 * @param {boolean} toggle on or off
	 * @intdocs
	 */
	public setFaceWakeup(toggle: boolean) {
		this.parent.log.info(`Circadian Face Wakeup: ${toggle}`);
		this.wakeWithFace = toggle;
	}

	/**
	 * Toggle whether heading a sound will wake Jibo up
	 * @param {boolean} toggle on or off
	 * @intdocs
	 */
	public setSoundWakeup(toggle: boolean) {
		this.parent.log.info(`Circadian Sound Wakeup: ${toggle}`);
		this.wakeWithSound = toggle;
	}

	/**
	 * Toggle whether both a face and a noise are needed to wake Jibo up
	 * @param {boolean} toggle on or off
	 * @intdocs
	 */
	public setWakeupFusion(toggle: boolean) {
		this.parent.log.info(`Circadian Wakeup Fusion: ${toggle}`);
		this.wakeEventFusion = toggle;
	}

	/**
	 * Set the duration after hearing the firest event that the second event will cause a fused event
	 * @param window fusion window in ms
	 * @intdocs
	 */
	public setFusionWindow(window: number) {
		this.parent.log.info(`Setting fusion window to ${window}.`);
		this.fusionWindowMs = window;
	}

	/**
	 * Show whether the circadian light rings should be shown or not.
	 */
	public showDebuggingLightRings(value: boolean) {
		this.parent.log.info(`Circadian light rings active: ${value}.`);
		this.useLEDForDebug = value;

		// immediately set the light ring for the current state
		const state = this.getCurrentCircadianState();
		if (state) {
			const color = this.circadianColorMap.get(state);
			color && jibo.expression.setLEDColor([color[0], color[1], color[2]]);
		}
	}

	/**
	 * Restart the circadian state machine with new durations input through the tunable debug interface
	 * @param {Map<CircadianState, number>} map of durations for each state
	 */
	public restartStateMachineWithDurations(durations: Array<[CircadianState, number]>) {
		this.parent.log.error('Restarting state machine with new durations. This should NEVER be called in production.');

		// The idle session needs to replace its promise with a new CircadianStateMachine using the adjusted circadian durations
		this.resetCircadianStateMachine(durations);
		this.parent.replaceSession();
	}

}
